#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 1e5+5;
const LL Inf = 0x3f3f3f3f3f3f3f3f;
LL n,to[N],val[N],Ans,du[N],Min;
queue<int> q;bool vis[N];
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void DFS(int u){
    vis[u]=1,Min=min(Min,val[u]);
    if(!vis[to[u]])DFS(to[u]);return;
}
int main(){
    n=read();
    for(int i=1;i<=n;i++)
        to[i]=read(),val[i]=read(),Ans+=val[i];
    for(int i=1;i<=n;i++)du[to[i]]++;
    for(int i=1;i<=n;i++)if(!du[i])q.push(i);
    while(!q.empty()){
        int u=q.front();vis[u]=1,q.pop();
        if(!(--du[to[u]]))q.push(to[u]);
    }for(int i=1;i<=n;i++)
        if(!vis[i])Min=Inf,DFS(i),Ans-=Min;
    cout<<Ans<<"\n";
    return 0;
}
